mapper.select:
SELECT pgao.id, pgao.authorized_object_id, pgao.object_type, CASE pgao.object_type WHEN 'user' THEN '用户' WHEN 'org' THEN '组织' WHEN 'station' THEN '驻地' WHEN 'position' THEN '岗位' ELSE pgao.object_type END AS object_type_name, pgao.authorized_object_id AS object_id, CASE pgao.object_type WHEN 'user' THEN (SELECT u.user_name FROM po_users u WHERE u.user_id = pgao.authorized_object_id) WHEN 'org' THEN (SELECT o.org_name FROM po_organization o WHERE o.org_id = pgao.authorized_object_id) WHEN 'station' THEN (SELECT p.station_name FROM po_station p WHERE p.station_id = pgao.authorized_object_id) ELSE NULL END AS object_name, pgao.effective_at, pgao.expires_at, pgao.create_time, pgao.create_by, u.user_name AS create_by_name FROM permission_group_authorized_objects pgao LEFT JOIN po_users u ON pgao.create_by = u.user_id
pgao.permission_group_id = #{query.permissionGroupId}
AND pgao.object_type = #{query.objectType}
AND ( (pgao.object_type = 'user' AND EXISTS ( SELECT 1 FROM po_users us WHERE us.user_id = pgao.authorized_object_id AND us.user_name LIKE CONCAT('%', #{query.objectName}, '%') )) OR (pgao.object_type = 'org' AND EXISTS ( SELECT 1 FROM po_organization os WHERE os.org_id = pgao.authorized_object_id AND os.org_name LIKE CONCAT('%', #{query.objectName}, '%') )) )
ORDER BY pgao.create_time DESC

SELECT COUNT(1)
FROM permission_group_authorized_objects
WHERE permission_group_id = #{permissionGroupId}

SELECT COUNT(1)
FROM permission_group_authorized_objects
WHERE permission_group_id = #{permissionGroupId}
AND object_type = #{objectType}
AND authorized_object_id = #{authorizedObjectId}

